import{_ as a,o as e,c as o,ae as s}from"./chunks/framework.BGHOrOyn.js";const u=JSON.parse('{"title":"BlackBox","description":"","frontmatter":{},"headers":[],"relativePath":"obd2/guides/hackster.io/blackbox.md","filePath":"obd2/guides/hackster.io/blackbox.md"}'),i={name:"obd2/guides/hackster.io/blackbox.md"};function r(d,t,n,p,l,c){return e(),o("div",null,[...t[0]||(t[0]=[s(`<h1 id="blackbox" tabindex="-1">BlackBox <a class="header-anchor" href="#blackbox" aria-label="Permalink to &quot;BlackBox&quot;">​</a></h1><p><a href="https://www.hackster.io/SURYATEJA/black-box-obd-pi-using-raspberry-pi-e363aa" target="_blank" rel="noreferrer">https://www.hackster.io/SURYATEJA/black-box-obd-pi-using-raspberry-pi-e363aa</a></p><h2 id="black-box-obd-pi-using-raspberry-pi" tabindex="-1">Black Box - OBD-Pi Using Raspberry Pi <a class="header-anchor" href="#black-box-obd-pi-using-raspberry-pi" aria-label="Permalink to &quot;Black Box - OBD-Pi Using Raspberry Pi&quot;">​</a></h2><p>Our project is a black box - OPD-Pi using Raspberry Pi.</p><p><a href="https://www.hackster.io/projects?difficulty=beginner" target="_blank" rel="noreferrer">Beginner</a>Full instructions provided1.5 hours37,921<img src="https://hackster.imgix.net/uploads/attachments/498045/blob_uSjDlEdmBX.blob?auto=compress%2Cformat&amp;w=900&amp;h=675&amp;fit=min" alt="Black Box - OBD-Pi Using Raspberry Pi"></p><h3 id="things-used-in-this-project" tabindex="-1">Things used in this project <a class="header-anchor" href="#things-used-in-this-project" aria-label="Permalink to &quot;Things used in this project&quot;">​</a></h3><table tabindex="0"><thead><tr><th><h4>Hardware components</h4></th><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td><img src="https://hackster.imgix.net/uploads/attachments/1206251/ph-a000066_iso_(1)_ztBMuBhMHo.jpg?auto=compress%2Cformat&amp;w=48&amp;h=48&amp;fit=fill&amp;bg=ffffff" alt="Arduino UNO"></td><td>01ea7ad981c84d2a9c62a593f3c85526</td><td>×</td><td>1</td><td></td></tr><tr><td><a href="https://www.hackster.io/arduino/products/arduino-uno1?ref=project-e363aa" target="_blank" rel="noreferrer">Arduino UNO</a></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td><img src="https://hackster.imgix.net/uploads/image/file/127603/Pi_3-02.jpg?auto=compress%2Cformat&amp;w=48&amp;h=48&amp;fit=fill&amp;bg=ffffff" alt="Raspberry Pi 3 Model B"></td><td>ffe0ee60875e47a6b99e9721e3a20467</td><td>×</td><td>1</td><td></td></tr><tr><td><a href="https://www.hackster.io/raspberry-pi/products/raspberry-pi-3-model-b?ref=project-e363aa" target="_blank" rel="noreferrer">Raspberry Pi 3 Model B</a></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td><img src="https://hackster.imgix.net/uploads/image/file/96109/Adafruit_Industries-ADA592-image_75px.jpg?auto=compress%2Cformat&amp;w=48&amp;h=48&amp;fit=fill&amp;bg=ffffff" alt="USB-A to Micro-USB Cable"></td><td>d3eb86c237244541a29ff2b8d92e1284</td><td>×</td><td>1</td><td></td></tr><tr><td>USB-A to Micro-USB Cable</td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td><h4>Software apps and online services</h4></td><td></td><td></td><td></td><td></td></tr><tr><td><img src="https://hackster.imgix.net/uploads/image/file/144203/IDE_web.jpg?auto=compress%2Cformat&amp;w=48&amp;h=48&amp;fit=fill&amp;bg=ffffff" alt="Arduino IDE"></td><td>08958ff02ced4cc3a1ba67dc4c32370c</td><td></td><td></td><td></td></tr><tr><td><a href="https://www.hackster.io/arduino/products/arduino-ide?ref=project-e363aa" target="_blank" rel="noreferrer">Arduino IDE</a></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td>c0b9ae8fbc4e434580cec6a3b13999b4</td><td></td><td></td><td></td></tr><tr><td>Raspberry Pi RASPIAN SOFTWARE</td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><h3 id="story" tabindex="-1">Story <a class="header-anchor" href="#story" aria-label="Permalink to &quot;Story&quot;">​</a></h3><p>In this tutorial, you will learn how to connect your Raspberry Pi to a Bluetooth OBD-II adapter and display real-time engine data to your car&#39;s aftermarket head unit!</p><h4 id="step-1-hardware-required" tabindex="-1">Step 1: Hardware Required: <a href="#toc-step-1--hardware-required-0" id="toc-step-1--hardware-required-0"></a> <a class="header-anchor" href="#step-1-hardware-required" aria-label="Permalink to &quot;Step 1: Hardware Required: &lt;a href=&quot;#toc-step-1--hardware-required-0&quot; id=&quot;toc-step-1--hardware-required-0&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><img src="https://hackster.imgix.net/uploads/attachments/498048/35_qkl4EXzAA5.jpg?auto=compress%2Cformat&amp;w=740&amp;h=555&amp;fit=max" alt=""></p><ul><li>Raspberry Pi Model B or B+</li><li>Aftermarket head unit (Note: Must support Auxiliary input)</li></ul><h4 id="step-2-what-is-obd-ii" tabindex="-1">Step 2: What Is OBD-II? <a href="#toc-step-2--what-is-obd-ii-1" id="toc-step-2--what-is-obd-ii-1"></a> <a class="header-anchor" href="#step-2-what-is-obd-ii" aria-label="Permalink to &quot;Step 2: What Is OBD-II? &lt;a href=&quot;#toc-step-2--what-is-obd-ii-1&quot; id=&quot;toc-step-2--what-is-obd-ii-1&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><img src="https://hackster.imgix.net/uploads/attachments/498049/36_f0o6sKnMQn.jpg?auto=compress%2Cformat&amp;w=740&amp;h=555&amp;fit=max" alt=""></p><p>OBD stands for On-Board Diagnostics, and this standard connector has been mandated in the US since 1996. Now you can think of OBD-II as an on-board computer system that is responsible for monitoring your vehicle’s engine, transmission, and emissions control components.</p><p>Vehicles that comply with the OBD-II standards will have a data connector within about 2 feet of the steering wheel. The OBD connector is officially called a SAE J1962 Diagnostic Connector, but is also known by DLC, OBD Port, or OBD connector. It has positions for 16 pins, and looks like this:</p><h4 id="step-3-pyobd" tabindex="-1">Step 3: PyOBD? <a href="#toc-step-3--pyobd-2" id="toc-step-3--pyobd-2"></a> <a class="header-anchor" href="#step-3-pyobd" aria-label="Permalink to &quot;Step 3: PyOBD? &lt;a href=&quot;#toc-step-3--pyobd-2&quot; id=&quot;toc-step-3--pyobd-2&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p><a href="https://github.com/sakurusurya2000/pyobd" target="_blank" rel="noreferrer">pyOBD</a> (aka pyOBD-II or pyOBD2) is an open source OBD-II (SAE-J1979) compliant scantool software written entirely in Python. It is designed to interface with low-cost ELM 32x OBD-II diagnostic interfaces such as ELM-USB. It will basically allow you to talk to your car&#39;s ECU, display fault codes, display measured values, read status tests, etc.</p><p>I took a fork of pyOBD’s software from their GitHub repository, <a href="https://github.com/peterh/pyobd" target="_blank" rel="noreferrer">https://github.com/peterh/pyobd,</a> and used this as the basis for my program.</p><p>The program will connect through the OBD-II interface, display the gauges available dependent on the particular vehicle and display real time engine data to the cars aftermarket head unit in an interactive GUI.</p><h4 id="step-4-software-installation" tabindex="-1">Step 4: Software Installation <a href="#toc-step-4--software-installation-3" id="toc-step-4--software-installation-3"></a> <a class="header-anchor" href="#step-4-software-installation" aria-label="Permalink to &quot;Step 4: Software Installation &lt;a href=&quot;#toc-step-4--software-installation-3&quot; id=&quot;toc-step-4--software-installation-3&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Before you start you will need a working install of Raspbian with network access.</p><p>We&#39;ll be doing this from a console cable connection, but you can just as easily do it from the direct HDMI/TV console or by SSH&#39;ing in. Whatever gets you to a shell will work!</p><p>Note: For the following command line instructions, do not type the &#39;#&#39;, that is only to indicate that it is a command to enter.</p><p>Before proceeding, run:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## sudo apt-get update</span></span>
<span class="line"><span>## sudo apt-get upgrade</span></span>
<span class="line"><span>## sudo apt-get autoremove</span></span>
<span class="line"><span>## sudo reboot</span></span></code></pre></div><p>Install these components using the command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## sudo apt-get install python-serial</span></span>
<span class="line"><span>## sudo apt-get install bluetooth bluez-utils blueman</span></span>
<span class="line"><span>## sudo apt-get install python-wxgtk2.8 python-wxtools wx2.8-i18n libwxgtk2.8-dev</span></span>
<span class="line"><span>## sudo apt-get install git-core</span></span>
<span class="line"><span>## sudo reboot</span></span></code></pre></div><h3 id="step-5-vehicle-installation" tabindex="-1">Step 5: Vehicle Installation <a href="#toc-step-5--vehicle-installation-4" id="toc-step-5--vehicle-installation-4"></a> <a class="header-anchor" href="#step-5-vehicle-installation" aria-label="Permalink to &quot;Step 5: Vehicle Installation &lt;a href=&quot;#toc-step-5--vehicle-installation-4&quot; id=&quot;toc-step-5--vehicle-installation-4&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><img src="https://hackster.imgix.net/uploads/attachments/498052/37_WW2u8kXwte.jpg?auto=compress%2Cformat&amp;w=740&amp;h=555&amp;fit=max" alt=""></p><p>The vehicle installation is quite simple.</p><ul><li>1. Insert the USB Bluetooth dongle into the Raspberry Pi along with the SD card.</li><li>2. Insert the OBD-II Bluetooth adapter into the SAE J196216 (OBD Port) connector.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## startx</span></span></code></pre></div><ul><li>7. Launch BlueZ, the Bluetooth stack for Linux. Pair + Trust your ELM327 Bluetooth Adapter and Connect To: SPP Dev. You should see the Notification &quot;Serial port connected to /dev/rfcomm0&quot;</li></ul><p>Note: Click the Bluetooth icon, bottom right (Desktop) to configure your device. Right click on your Bluetooth device to bring up Connect To: SPP Dev.</p><ul><li>8. Open up Terminal and run:</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## cd pyobd-pi</span></span>
<span class="line"><span>## sudo su</span></span>
<span class="line"><span>## python obd_gui.py</span></span></code></pre></div><p>Use the Left and Right arrow keys to cycle through the gauge display.To exit the program just press Control and C or Alt and Esc.</p><h3 id="step-6-data-logging" tabindex="-1">Step 6: Data Logging <a href="#toc-step-6--data-logging-5" id="toc-step-6--data-logging-5"></a> <a class="header-anchor" href="#step-6-data-logging" aria-label="Permalink to &quot;Step 6: Data Logging &lt;a href=&quot;#toc-step-6--data-logging-5&quot; id=&quot;toc-step-6--data-logging-5&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p><img src="https://hackster.imgix.net/uploads/attachments/498053/38_GAHCE759Al.jpg?auto=compress%2Cformat&amp;w=740&amp;h=555&amp;fit=max" alt=""></p><p>If you would like to log your data run:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## cd pyobd-pi</span></span>
<span class="line"><span>## python obd_recorder.py</span></span></code></pre></div><p>The logged data file will be saved under: <em>/home/username/pyobd-pi/log/</em><strong>Enjoy and drive safe!</strong></p>`,43)])])}const g=a(i,[["render",r]]);export{u as __pageData,g as default};
